# --- Caching Decorator for functions (e.g., database queries) ---
def cache_result(key_prefix, ttl=300):
    def decorator(func):
        def wrapper(*args, **kwargs):
            cache_key = f"{key_prefix}:{func.__name__}:{json.dumps(args)}:{json.dumps(kwargs)}"
            
            # Try to get data from cache
            cached_data = memcached_client.get(cache_key)
            if cached_data:
                # print(f"Cache HIT for {cache_key}") # For debugging
                try:
                    return json.loads(cached_data)
                except json.JSONDecodeError:
                    # If cached data is corrupted or not JSON, recompute
                    pass

            # Cache MISS, execute the original function
            # print(f"Cache MISS for {cache_key}") # For debugging
            result = func(*args, **kwargs)
            
            # Store the result in cache
            memcached_client.set(cache_key, json.dumps(result), expire=ttl)
            return result
        return wrapper
    return decorator

